var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"역병의 마수가 이곳까지 덮친 것인가?","JPN":"疫病の魔手がここまで押し寄せてきたのか？","ENG":"Has the plague already reached these lands?","TWN":"瘟疫已蔓延至此了？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"마왕이 사라졌음에도 역병의 기세는 조금도 누그러들지 않았구나.","JPN":"魔王が消えても、疫病の勢いは少しも収まっていないのだな。","ENG":"Even with the Demon Lord gone, the plague has not slowed down at all.","TWN":"魔王消失後，瘟疫傳播的趨勢也絲毫沒有減弱。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"…예하! 여기요!","JPN":"……猊下！　ここです！","ENG":"...Your Eminence! Over here!","TWN":"……主教！這邊！"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"아직 살아 계신 분을 찾았어요!","JPN":"まだ生きている方を見つけました！","ENG":"I found someone still alive!","TWN":"找到了倖存者！"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"WOMEN_CULTIST_NULL_EXTRA","text":{"KOREA":"커억… 컥, 컥…","JPN":"ぐっ……がはっ……くうっ……","ENG":"Kurgh... K-kuh...","TWN":"咳……咳咳……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MONSTER_MOVEMENT_11"},{"id":"L12_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"이미 목덜미 아래로는 전부 검게 잠식되었군.","JPN":"既に首から下は黒く侵食されておるな。","ENG":"The plague has already consumed her body from the neck down.","TWN":"脖子以下的身體已經被徹底侵蝕了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"마물로부터 안전한 곳에 숨어있었지만, 역병을 피하진 못했구나.","JPN":"村から逃げ出し安全な場所に隠れていても、疫病からは逃れられなかったのか。","ENG":"Though she was safe from the monsters, she could not hide from the plague.","TWN":"雖然躲到了一個遠離怪物的地方，但還是沒能逃過瘟疫的侵襲。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"어, 얼른 데려가죠! 교단까지 조금 멀긴 하지만, 도착하면 의사분들이 도와줄 거예요!","JPN":"は、早く連れて行きましょう！　教団までは距離がありますが、行けばお医者さんが助けてくれるはずです！","ENG":"W-we need to get her help! The Order is a little far, but I'm sure the doctors will help her once we bring her to them!","TWN":"快、快帶走吧！雖然這裡離教團有點遠，但至少能得到醫生們的幫助！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"역병을 치료할 수 있는 의사는 없다.","JPN":"疫病を治療できる医者はおらん。","ENG":"There is no doctor who can cure the plague.","TWN":"沒有醫生能治癒瘟疫。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"이 여인을 데려가봐야 주민들의 역병에 대한 두려움만 자극할 뿐이겠지.","JPN":"この女を連れて行っても疫病に対する住民たちの恐怖心を刺激するだけであろう。","ENG":"We will only instill more fear of the plague in the residents if we bring her with us.","TWN":"把人帶走只會加劇村民對瘟疫的恐懼。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"그럼… 어떻게 하죠?","JPN":"では……どうしましょう。","ENG":"Then... What do we do?","TWN":"那麼……我們該怎麼辦？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"지금 할 수 있는 최선은, 병자가 변이를 겪으며 얻는 고통을 조금이라도 덜어주는 것이다.","JPN":"今できることは、病人が変異する時の苦痛を少しでも和らげてあげることだ。","ENG":"The best we can do for her is to spare her from the pain of transformation.","TWN":"我們現在能做的就是盡可能減輕病人在變異過程中的痛苦。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"WOMEN_CULTIST_NULL_EXTRA","text":{"KOREA":"아… 아아….","JPN":"あ……ああ……","ENG":"Ah... Ahh...","TWN":"啊……啊……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"WOMEN_CULTIST_NULL_EXTRA","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L25_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"빛의 품에서, 상냥한 안식을.","JPN":"光に包まれ、優しい安らぎを。","ENG":"May you find a peaceful rest in the light's embrace.","TWN":"在光明的懷抱中安息吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"…죄송해요. 제가 했어야 하는 건데.","JPN":"……ごめんなさい。私がやらなければいけないのに。","ENG":"...I'm sorry. I should've been the one to do it.","TWN":"……對不起，本應該是我來做的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"이또한 나의 책무이니. 신경 쓰지 말아라.","JPN":"これもまた、我の責務だ。気にするな。","ENG":"This is my responsibility. No concern of yours.","TWN":"這也是我的職責。沒關係"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"이는 역병을 물리치는 날까지 교단이 감내해야 할 시련일지니.","JPN":"これは疫病に打ち勝つその日まで、教団が受け入れなければならない試練であろう。","ENG":"The Order must endure this trial until the plague is fully rid from this world.","TWN":"這是教團必須經受的考驗，直到徹底消滅掉瘟疫。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"이곳에도 네가 찾는 가족은 없는 것 같구나.","JPN":"ここにもそなたが探している家族はいないようだな。","ENG":"It seems your sister is not here.","TWN":"這裡似乎也沒有你要找的家人。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"…네.","JPN":"……はい。","ENG":"...No.","TWN":"……是的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"그런데, 이곳의 마을입구에는 언니가 하고 있던 목걸이랑 똑같은 장식이 걸려 있었어요.","JPN":"ところで、この村の入口にお姉さんがつけていた首飾りと同じ装飾がありました。","ENG":"But I saw an ornament at the entrance of this village that looked exactly like my sister's necklace.","TWN":"但是這個村子的入口掛著一個和我姊姊戴的項鍊一模一樣的裝飾。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"믿는 자들의 상징이로군.","JPN":"信じる者たちの象徴だな。","ENG":"A symbol of faith, I see.","TWN":"信徒的象徵。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"세상엔 다양한 형태의 믿음이 있지만, 우리는 교단 이외의 것을 이단이라고 부른다.","JPN":"この世には様々な形の信仰があるが、我々は教団以外のものは異端と呼んでいる。","ENG":"Although there are various forms of faith in this world, the Order has decided to label everything except ours as pagan.","TWN":"世界上有許多不同的形態和信仰，我們把教團之外的所有東西都稱為異端。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"으음… 믿음이란 건 복잡한 건가 보네요.","JPN":"う～ん……信仰とは複雑なんですね。","ENG":"Hmm... Faith seems to be more complicated than I thought.","TWN":"嗯……看來信仰是個複雜的東西。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"전 그냥 언니만 곁에 있어도 충분한데.","JPN":"私はただお姉さんがいてくれればそれで十分なのに。","ENG":"Just having my sister by my side would be enough for me.","TWN":"我只需要我姊姊在身邊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"마지막 분까지 전부 묻어드린 것 같네요.","JPN":"最後に亡くなった方まで全部埋めましたね。","ENG":"I think we buried everyone.","TWN":"最後一個人也埋葬好了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"다들… 편히 잠드셨으면 좋겠는데…","JPN":"皆さん……安らかに眠れるなら良いのですが……","ENG":"I hope... they rest in peace...","TWN":"願所有人都能安息……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"죽음은 안타까운 일이지만, 더 이상의 고통은 없을 것이다.","JPN":"死とは残念なものだが、これ以上の苦痛はなかろう。","ENG":"Death is unfortunate, but there will be no more pain.","TWN":"死亡是不幸的，但至少不必再承受痛苦。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"죽으면… 그걸로 끝인 걸까요?","JPN":"死ねば……それで全てが終わるのですか？","ENG":"Is that it... once you die?","TWN":"如果死了……一切就都結束了嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_DESPAIR"}}}},{"id":"L47_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"성서에선 신실한 자가 죽으면 빛 너머의 낙원으로 향할 것이라 말하지.","JPN":"聖書では信者が死ぬと、光の彼方の楽園へ向かうことになると語っている。","ENG":"The bible says those who are devout will reach paradise beyond the light.","TWN":"聖書裡說，信徒死後會前往一個光明彼岸的樂園。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_DESPAIR"}}}},{"id":"L48_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"언니는 이교도이니까, 낙원에 가지 못하는 걸까요?","JPN":"お姉さんは異教徒だから、楽園には行けないのでしょうか。","ENG":"But since my sister is a pagan, does that mean she can't go to paradise?","TWN":"我姊姊是異教徒，是不是去不了樂園？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"우리는 죽음 이후의 것들에 아무런 개입도 할 수 없다.","JPN":"我らは死の後のことについては、何も介入できない。","ENG":"We cannot intervene in events after death.","TWN":"我們無法介入人死後的事情。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"너의 누이를 찾는 것처럼, 우린 그저 산 자들의 구원을 위해 노력할 뿐.","JPN":"そなたの姉を探すように、我らはただ生きている者を救うため努力するだけなのだ。","ENG":"Much like how you are looking for your sister, we do what we can to bring salvation to the living.","TWN":"就像尋找你的姊姊一樣，我們只能為拯救活人而努力。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"그러네요. 산 사람은 산 사람을 위해서… 좌절에 빠져있으면 안되는 거겠죠.","JPN":"そうですね。生きている人のために……落ちこんでいてはいけませんね。","ENG":"You're right. The living must fight for the living... There's no need to be in despair.","TWN":"是啊，活著的人還是要為活人努力……不能沉浸在沮喪中。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_DESPAIR"}}}},{"id":"L2_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"그럼 얼른 가요!","JPN":"それじゃ、さっさと行きましょう！","ENG":"Then let's keep going!","TWN":"那我們走吧！"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"아우드라.","JPN":"アウドラ。","ENG":"Audra.","TWN":"奧德拉。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"네?","JPN":"はい？","ENG":"Yes?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"그대의 누이는 어떤 사람이지?","JPN":"そなたの姉はどんな人物だ？","ENG":"Could you tell me about your sister?","TWN":"你姊姊是什麼樣的人？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"으음- 언니는 부지런하고, 약차를 잘 달이고, 이웃들에게도 친절해요.","JPN":"う～ん。お姉さんは働き者で、薬茶を煎じるのが上手で、近所の人にも優しいです。","ENG":"Hmm... My sister is diligent, kind to her neighbors, and makes really good medicinal tea.","TWN":"嗯——我姊姊很勤快，泡得一手好茶，對鄰居也很友好。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"식물에 대해 마을 누구보다 잘 알고, 장사 수완도 엄청 좋아요.","JPN":"植物に関しては誰よりも詳しくて、商売上手でもあります。","ENG":"She knows more about plants than anyone else in the village, and she also has a knack for business.","TWN":"她對植物的了解比鎮上任何人都多，而且還是個很出色的商人。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"맨날 절 야단치지만, 마음은 엄청 따뜻한 사람이고요.","JPN":"いつも私を叱っていたけど、心はとても温かい人なんです。","ENG":"Although she scolds me every day, I know her heart is in the right place.","TWN":"她雖然總是責備我，但有一顆溫柔的心。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"아, 물론! 야단치는 건 제가 실수를 많이 해서 그런 거지만요, 헤헤.","JPN":"あ、もちろん！　叱られたのは私がたくさんミスをしたからですけどね、へへ。","ENG":"Oh, still! Her scolding is because of all the mistakes I make. Heh heh.","TWN":"喔，當然！她責備我是因為我總是惹禍，嘿嘿。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"그녀가 범죄를 저지른 적은 없나?","JPN":"彼女は犯罪を犯したことはないのか？","ENG":"Has she committed any crimes?","TWN":"她犯過什麼罪嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"네? 그게 무슨 말씀이세요?","JPN":"はい？　それはどういうことですか？","ENG":"Huh? What do you mean by that?","TWN":"嗯？什麼意思？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"많은 이교도인들이 교리에 어긋난 범법을 저질러 재판을 거쳐 교화조치를 받게 되지.","JPN":"多くの異教徒は教理に反する違法を犯し、裁判を経て教化に基づく措置を受ける。","ENG":"Many pagans are put on trial and undergo edification for the crimes they have committed against the doctrine.","TWN":"許多異教徒因違背教義犯下罪過而受審，並受到教化。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"만약 그녀가 죄를 저질렀다면 지금쯤 신전의 교화소에 있을 테니, 이는 네 누이를 찾을 단서가 될 수도 있다.","JPN":"もし彼女が罪を犯しているのであれば、いまごろ神殿の監獄にいるはず。そなたの姉を探す手がかりになるであろう。","ENG":"If she has committed any sins, then she should be in the temple's correctional center, and this might be a clue to finding your sister.","TWN":"如果她犯了罪，現在應該在聖殿的教化所裡，這可能是找到你姊姊的線索。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"글쎄요. 언니는 비밀이 많은 사람이었지만…","JPN":"そうですか。お姉さんは謎が多かったけど……","ENG":"I'm not sure. My sister had a lot of secrets, but...","TWN":"我姊姊是個很神秘的人，但是……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"그래도 감옥에 갈 정도로 나쁜 사람은 아닐 거예요.","JPN":"でも、監獄に行くほど悪い人ではないはずです。","ENG":"I don't think she was a bad enough person to go to jail.","TWN":"並沒有壞到坐牢的地步。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"그야 언니는 혈육도 아닌 저를 어릴 때부터 거둬 키워준 소중한 가족인 걸요!","JPN":"だって、お姉さんは血の繋がりのない私を子どもの頃から育ててくれた大切な家族ですから！","ENG":"You see, she's my precious family who has raised me since I was a child, despite the fact that I'm not even related to her!","TWN":"她把沒有任何血緣關係的我撫養長大，是我珍貴的家人！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"너의 감정을 상하게 했다면, 사죄하마.","JPN":"そなたの気分を害したのであれば、謝ろう。","ENG":"I apologize if I hurt your feelings.","TWN":"要是我的問題有傷害到你，我向你道歉。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"아… 괜찮아요.","JPN":"あ……平気です。","ENG":"Oh... It's all right.","TWN":"啊……沒關係。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"그래도 예하 말씀처럼 언니가 신전처럼 안전한 곳에 있을 지도 모른다고 생각하니, 마음이 편해졌어요.","JPN":"でも、猊下がおっしゃったようにお姉さんが神殿のような安全な場所にいるかもしれないと思ったら、少しは気が楽になりました。","ENG":"But I feel a little at ease after what you said, about how she might be in a safe place like the temple.","TWN":"不過想到我姊姊可能在一個安全的地方，就像你說的神殿，我可以稍微放下心了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"너는 가족을 찾기 위해 내 원정을 도왔고, 그 의무를 훌륭히 이행해주었다.","JPN":"そなたは家族を探すために我の遠征に力を貸し、その義務を見事全うした。","ENG":"To find your family, you offered your assistance on my expedition and performed that mission with excellence.","TWN":"你為了尋找家人協助了我的遠征，並且很出色地完成了這一職責。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"나 또한 반드시 네 가족을 찾을 테니, 걱정 말 거라.","JPN":"我も必ずそなたの家族を探してやろう、案ずるな。","ENG":"I shall find your family no matter what, so do not worry.","TWN":"所以別擔心，我也會幫你找到你的家人的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"네, 예하!","JPN":"はい、猊下！","ENG":"Yes, Your Eminence!","TWN":"是，主教！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};